import { describe, test, expect } from "vitest";

import {
  widenGeneratedTypes,
  computeRequestOnlyComponentNames,
  verifyNoSharedEnumBearingSchemas,
} from "../../scripts/widen-response-enums.mjs";

function enumFile(name: string, members: string[]) {
  const body = members.map((m) => `  ${m}: '${m}',`).join("\n");
  return [
    "/**",
    " * Generated by orval",
    " */",
    "",
    `export type ${name} = typeof ${name}[keyof typeof ${name}];`,
    "",
    "",
    "// eslint-disable-next-line @typescript-eslint/no-redeclare",
    `export const ${name} = {`,
    body,
    "} as const;",
    "",
  ].join("\n");
}

describe("widenGeneratedTypes", () => {
  test("widens a component-schema (response) enum, leaves a *Body and a *Params enum closed", () => {
    const files = new Map([
      // Response entity Device.deviceClass — mirrors the real deviceDeviceClass.ts shape.
      [
        "device.ts",
        [
          "import type { DeviceDeviceClass } from './deviceDeviceClass';",
          "",
          "export interface Device {",
          "  deviceClass?: DeviceDeviceClass;",
          "}",
          "",
        ].join("\n"),
      ],
      [
        "deviceDeviceClass.ts",
        enumFile("DeviceDeviceClass", [
          "device",
          "printer",
          "rmmnetworkdevice",
        ]),
      ],

      // An anonymous request body's own hoisted enum field.
      [
        "createWidgetBody.ts",
        [
          "import type { CreateWidgetBodyStatus } from './createWidgetBodyStatus';",
          "",
          "export interface CreateWidgetBody {",
          "  status?: CreateWidgetBodyStatus;",
          "}",
          "",
        ].join("\n"),
      ],
      [
        "createWidgetBodyStatus.ts",
        enumFile("CreateWidgetBodyStatus", ["active", "inactive"]),
      ],

      // A query-parameter type's own hoisted enum field.
      [
        "listWidgetsParams.ts",
        [
          "import type { ListWidgetsOrder } from './listWidgetsOrder';",
          "",
          "export type ListWidgetsParams = {",
          "  order?: ListWidgetsOrder;",
          "};",
          "",
        ].join("\n"),
      ],
      ["listWidgetsOrder.ts", enumFile("ListWidgetsOrder", ["asc", "desc"])],
    ]);

    const widened = widenGeneratedTypes(files, new Set());

    expect(widened.get("deviceDeviceClass.ts")).toContain(
      "export type DeviceDeviceClass = typeof DeviceDeviceClass[keyof typeof DeviceDeviceClass] | (string & {});",
    );
    expect(widened.get("createWidgetBodyStatus.ts")).toBe(
      files.get("createWidgetBodyStatus.ts"),
    );
    expect(widened.get("listWidgetsOrder.ts")).toBe(
      files.get("listWidgetsOrder.ts"),
    );
    // Non-enum files pass through untouched.
    expect(widened.get("device.ts")).toBe(files.get("device.ts"));

    // Second pass over the widened output is a no-op (idempotent).
    const secondPass = widenGeneratedTypes(widened, new Set());
    for (const [fileName, content] of widened) {
      expect(secondPass.get(fileName)).toBe(content);
    }
  });

  test("excludes a named-component request-only root (and its hoisted children) via the spec-derived set, not a suffix", () => {
    const files = new Map([
      [
        "warranty.ts",
        [
          "import type { WarrantyLevel } from './warrantyLevel';",
          "",
          "export interface Warranty {",
          "  level?: WarrantyLevel;",
          "}",
          "",
        ].join("\n"),
      ],
      ["warrantyLevel.ts", enumFile("WarrantyLevel", ["bronze", "gold"])],
    ]);

    // `Warranty` carries no Body/Params/etc. suffix, so only the spec-derived request-only set
    // (computed from requestBody-vs-response reachability — see the next describe block) can
    // correctly identify it as request-side.
    const withoutSpecKnowledge = widenGeneratedTypes(files, new Set());
    expect(withoutSpecKnowledge.get("warrantyLevel.ts")).toContain(
      "| (string & {})",
    );

    const withSpecKnowledge = widenGeneratedTypes(files, new Set(["Warranty"]));
    expect(withSpecKnowledge.get("warrantyLevel.ts")).toBe(
      files.get("warrantyLevel.ts"),
    );
  });
});

describe("computeRequestOnlyComponentNames", () => {
  function specWith({
    requestRef,
    alsoInResponse,
  }: {
    requestRef: string;
    alsoInResponse: boolean;
  }) {
    return {
      paths: {
        "/write-only": {
          post: {
            requestBody: {
              content: {
                "application/json": {
                  schema: { $ref: `#/components/schemas/${requestRef}` },
                },
              },
            },
            responses: {
              "200": {
                content: { "application/json": { schema: { type: "object" } } },
              },
            },
          },
        },
        ...(alsoInResponse
          ? {
              "/read-only": {
                get: {
                  responses: {
                    "200": {
                      content: {
                        "application/json": {
                          schema: {
                            $ref: `#/components/schemas/${requestRef}`,
                          },
                        },
                      },
                    },
                  },
                },
              },
            }
          : {}),
      },
      components: {
        schemas: { [requestRef]: { type: "object", properties: {} } },
      },
    };
  }

  test("includes a component reachable only from a requestBody", () => {
    const spec = specWith({ requestRef: "Warranty", alsoInResponse: false });
    expect(computeRequestOnlyComponentNames(spec)).toEqual(
      new Set(["Warranty"]),
    );
  });

  test("excludes a component reachable from both a requestBody and a response", () => {
    const spec = specWith({ requestRef: "Udf", alsoInResponse: true });
    expect(computeRequestOnlyComponentNames(spec)).toEqual(new Set());
  });

  test("PascalCases a spec schema name containing spaces to match Orval's generated type name", () => {
    const spec = specWith({
      requestRef: "Variable Creation Request",
      alsoInResponse: false,
    });
    expect(computeRequestOnlyComponentNames(spec)).toEqual(
      new Set(["VariableCreationRequest"]),
    );
  });
});

describe("verifyNoSharedEnumBearingSchemas", () => {
  test("throws when a requestBody directly $refs an enum-bearing schema also used in a response", () => {
    const spec = {
      paths: {
        "/proxy": {
          post: {
            requestBody: {
              content: {
                "application/json": {
                  schema: { $ref: "#/components/schemas/ProxySettings" },
                },
              },
            },
          },
        },
        "/site": {
          get: {
            responses: {
              "200": {
                content: {
                  "application/json": {
                    schema: { $ref: "#/components/schemas/ProxySettings" },
                  },
                },
              },
            },
          },
        },
      },
      components: {
        schemas: {
          ProxySettings: {
            type: "object",
            properties: { type: { type: "string", enum: ["http", "socks4"] } },
          },
        },
      },
    };

    expect(() => verifyNoSharedEnumBearingSchemas(spec)).toThrow(
      /ProxySettings/,
    );
    expect(() => verifyNoSharedEnumBearingSchemas(spec)).toThrow(
      /POST \/proxy/,
    );
    expect(() => verifyNoSharedEnumBearingSchemas(spec)).toThrow(/GET \/site/);
  });

  test("throws when a requestBody reaches an enum-bearing schema only transitively (nested property $ref)", () => {
    const spec = {
      paths: {
        "/site": {
          put: {
            requestBody: {
              content: {
                "application/json": {
                  schema: { $ref: "#/components/schemas/CreateSiteRequest" },
                },
              },
            },
          },
          get: {
            responses: {
              "200": {
                content: {
                  "application/json": {
                    schema: { $ref: "#/components/schemas/ProxySettings" },
                  },
                },
              },
            },
          },
        },
      },
      components: {
        schemas: {
          CreateSiteRequest: {
            type: "object",
            properties: {
              proxySettings: { $ref: "#/components/schemas/ProxySettings" },
            },
          },
          ProxySettings: {
            type: "object",
            properties: { type: { type: "string", enum: ["http", "socks4"] } },
          },
        },
      },
    };

    expect(() => verifyNoSharedEnumBearingSchemas(spec)).toThrow(
      /ProxySettings/,
    );
  });

  test("does not throw when a shared component is enum-free", () => {
    const spec = {
      paths: {
        "/quickjob": {
          put: {
            requestBody: {
              content: {
                "application/json": {
                  schema: { $ref: "#/components/schemas/JobComponentVariable" },
                },
              },
            },
          },
        },
        "/job": {
          get: {
            responses: {
              "200": {
                content: {
                  "application/json": {
                    schema: {
                      $ref: "#/components/schemas/JobComponentVariable",
                    },
                  },
                },
              },
            },
          },
        },
      },
      components: {
        schemas: {
          JobComponentVariable: {
            type: "object",
            properties: { name: { type: "string" }, value: { type: "string" } },
          },
        },
      },
    };

    expect(() => verifyNoSharedEnumBearingSchemas(spec)).not.toThrow();
  });
});
